#include <iostream>
#include <string>
#include <regex>

// Function converting markdown formatted text to HTML formatted text
std::string markdownToHtml(std::string& markdown) {
    // Regex and replace for headers of levels H1 to H6
    std::regex headerRegex(R"(^(#{1,6})\s*(.*))", std::regex_constants::multiline);
    std::string html = std::regex_replace(markdown, headerRegex, [](const std::smatch& m) {
        size_t level = m.str(1).size();
        return "<h" + std::to_string(level) + ">" + m.str(2).trim() + "</h" + std::to_string(level) + ">\n";
    });

    // Regex and replace for bold text
    std::regex boldRegex(R"(\*\*(.*?)\*\*)");
    html = std::regex_replace(html, boldRegex, "<strong>$1</strong>");

    // Regex and replace for italic text
    std::regex italicRegex(R"(\*(.*?)\*)");
    html = std::regex_replace(html, italicRegex, "<em>$1</em>");

    // Regex and replace for links
    std::regex linkRegex(R"(\[([^\]]+)\]\(([^)]+)\))");
    html = std::regex_replace(html, linkRegex, "<a href=\"$2\">$1</a>");

    // Convert standalone lines into paragraphs
    std::regex pRegex(R"(^\s*(\S[^\n]*\S)\s*$)", std::regex_constants::multiline);
    html = std::regex_replace(html, pRegex, "<p>$1</p>");

    return html;
}

// Example main to demonstrate the function
int main() {
    std::string markdownText = "# Welcome\n"
                               "## Subheader Example\n"
                               "Welcome to **Markdown to HTML** conversion! This is a simple *example*.\n"
                               "Find more about Markdown [here](https://en.wikipedia.org/wiki/Markdown).\n"
                               "Random text";

    std::string htmlText = markdownToHtml(markdownText);
    std::cout << htmlText << std::endl;

    return 0;
}
```

